  'kds.import_usei18n_from_vue': "import { useI18n } from \"vue-i18n\";\nconst { t } = useI18n();\nimport { ref, onMounted, onUnmounted, computed, watch } from \"vue\";\nimport { supabase } from \"@/lib/supabase\";\nimport { useRealtime } from \"@/composables/useRealtime\";\nimport { useOrder } from \"@/composables/useOrder\";\nimport { useBranch } from \"@/composables/useBranch\";\nimport {\n  mockTickets,\n  mockGrillRequests,\n  mock86dItems,\n} from \"@/data/mockKitchenData\";\nimport type { OrderStatus } from \"@/types/database\";\nimport { useKitchenStore } from \"@/stores/kitchen\";\nimport HeaderButtons from \"@/components/HeaderButtons.vue\";\n\nconst { watchTable } = useRealtime();\nconst { loading } = useOrder();\n\nconst kitchenStore = useKitchenStore();\n\n// Types\ninterface OrderItem {\n  id: string;\n  name: string;\n  qty: number;\n  note?: string;\n  done: boolean;\n}\n\ninterface Order {\n  id: string;\n  table: string;\n  time: string; // HH:mm\n  timestamp: number;\n  waitTime: number; // in seconds\n  items: OrderItem[];\n  status: \"pending\" | \"preparing\" | \"ready\" | \"done\";\n}\n\n// Grill & Coal Request structure\ninterface GrillRequest {\n  id: string;\n  table: string;\n  type: \"GrillChange\" | \"CoalRefill\";\n  status: \"Pending\" | \"Inprogress\" | \"Completed\";\n  priority: \"Normal\" | \"Urgent\";\n  createdAt: number;\n  timeLeft?: number; // count down seconds\n  timer?: any; // interval handler\n}\n\n// Stations config mapping\nconst stations = [\n  { key: \"ALL\", label: \"Tất cả trạm\" },\n  { key: \"Grill\", label: \"Bếp Nướng\" },\n  { key: \"Hotpot\", label: \"Bếp Lẩu\" },\n  { key: \"Cold\", label: \"Bếp Lạnh\" },\n  { key: \"Fried\", label: \"Bếp Chiên\" },\n  { key: \"Bar\", label: \"Bar/Đồ uống\" },\n];\n\n// State variables\nconst orders = ref",
